import React, { useEffect, useState } from "react";
import "./Internship.css";

export default function Internship() {
  const [internships, setInternships] = useState([]);
  const [showModal, setShowModal] = useState(false);
  const [newInternship, setNewInternship] = useState({
    title: "",
    company: "",
    location: "",
    stipend: "",
    duration: "",
    applyLink: "",
  });

  const user = JSON.parse(localStorage.getItem("user")); // ✅ Use correct key

  // Dummy fetch simulation
  useEffect(() => {
    // You can replace this with real API call
    const stored = JSON.parse(localStorage.getItem("internships")) || [];
    setInternships(stored);
  }, []);

  const handleOpenModal = () => setShowModal(true);
  const handleCloseModal = () => setShowModal(false);

  const handleChange = (e) => {
    setNewInternship({ ...newInternship, [e.target.name]: e.target.value });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    const updated = [...internships, newInternship];
    setInternships(updated);
    localStorage.setItem("internships", JSON.stringify(updated));
    setNewInternship({
      title: "",
      company: "",
      location: "",
      stipend: "",
      duration: "",
      applyLink: "",
    });
    setShowModal(false);
  };

  return (
    <div className="internship-page">
      <h2>Internship Opportunities</h2>

      {(user?.role === 'admin' || user?.role === 'hr') && (
        <button onClick={handleOpenModal} className="add-internship-btn">
          + Add Internship
        </button>
      )}

      <div className="internship-list">
        {internships.length === 0 ? (
          <p>No internships available.</p>
        ) : (
          internships.map((intern, index) => (
            <div key={index} className="internship-card">
              <h3>{intern.title}</h3>
              <p><strong>Company:</strong> {intern.company}</p>
              <p><strong>Location:</strong> {intern.location}</p>
              <p><strong>Stipend:</strong> {intern.stipend}</p>
              <p><strong>Duration:</strong> {intern.duration}</p>
              <a href={intern.applyLink} target="_blank" rel="noopener noreferrer">Apply Now</a>
            </div>
          ))
        )}
      </div>

      {showModal && (
        <div className="modal-overlay">
          <div className="modal">
            <h3>Add Internship</h3>
            <form onSubmit={handleSubmit}>
              <input
                type="text"
                name="title"
                placeholder="Job Title"
                value={newInternship.title}
                onChange={handleChange}
                required
              />
              <input
                type="text"
                name="company"
                placeholder="Company Name"
                value={newInternship.company}
                onChange={handleChange}
                required
              />
              <input
                type="text"
                name="location"
                placeholder="Location"
                value={newInternship.location}
                onChange={handleChange}
              />
              <input
                type="text"
                name="stipend"
                placeholder="Stipend"
                value={newInternship.stipend}
                onChange={handleChange}
              />
              <input
                type="text"
                name="duration"
                placeholder="Duration"
                value={newInternship.duration}
                onChange={handleChange}
              />
              <input
                type="url"
                name="applyLink"
                placeholder="Application Link"
                value={newInternship.applyLink}
                onChange={handleChange}
                required
              />
              <button type="submit">Save</button>
              <button type="button" onClick={handleCloseModal}>
                Cancel
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
